3	// Eğer CORS hatası alırsan buraya kendi proxy adresini yazabilirsin
4	export const PROXY = "";
5	
6	// Alternative Binance API Base URLs for fallback
7	const F_BASES = [
8	  "https://fapi.binance.com",
9	  "https://fapi1.binance.com",
10	  "https://fapi2.binance.com",
11	  "https://fapi3.binance.com"
12	];
13	
14	const S_BASES = [
15	  "https://api.binance.com",
16	  "https://api1.binance.com",
17	  "https://api2.binance.com",
18	  "https://api3.binance.com"
19	];
20	
21	/**
22	 * Helper: Dakika başlangıcı UTC ms
23	 */
24	export function msMinuteStartUTC(tsStr) {
25	  const d = new Date(tsStr + "Z");
26	  return Date.UTC(
27	    d.getUTCFullYear(),
28	    d.getUTCMonth(),
29	    d.getUTCDate(),
30	    d.getUTCHours(),
31	    d.getUTCMinutes(),
32	    0,
33	    0
34	  );
35	}
36	
37	/**
38	 * Helper: Format UTC datetime as YYYY-MM-DD HH:mm:ss UTC+0
39	 */
40	function fmtUTC(ms) {
41	  const d = new Date(ms);
42	  const pad = (n) => String(n).padStart(2, "0");
43	  return (
44	    `${d.getUTCFullYear()}-${pad(d.getUTCMonth() + 1)}-${pad(d.getUTCDate())} ` +
45	    `${pad(d.getUTCHours())}:${pad(d.getUTCMinutes())}:${pad(d.getUTCSeconds())} UTC+0`
46	  );
47	}
48	
49	/**
50	 * Helper: Format MS as HH:mm:ss for short display
51	 */
52	function fmtFreq(ms) {
53	  const d = new Date(ms);
54	  const pad = (n) => String(n).padStart(2, "0");
55	  return `${pad(d.getUTCHours())}:${pad(d.getUTCMinutes())}:${pad(d.getUTCSeconds())}`;
56	}
57	
58	/**
59	 * Helper: Fetch with fallback across multiple base URLs
60	 */
61	async function fetchWithFallback(bases, path, kind = "") {
62	  let lastError = null;
63	  for (const base of bases) {
64	    try {
65	      const url = `${PROXY}${base}${path}`;
66	      const res = await fetch(url);
67	      if (res.ok) return await res.json();
68	
69	      if (res.status === 429) throw new Error("Binance Rate Limit (429). Please wait a moment.");
70	      if (res.status === 418) throw new Error("IP Banned (418). Please use a VPN or Proxy.");
71	      if (res.status === 451) throw new Error("Regional Block (451). This API is restricted in your region. Use a Proxy.");
72	
73	      lastError = new Error(`HTTP Error ${res.status}: ${res.statusText}`);
74	    } catch (err) {
75	      lastError = err;
76	      // Continue to next base if it's a network error or transient failure
77	      if (err.message.includes("Rate Limit") || err.message.includes("IP Banned") || err.message.includes("Regional Block")) {
78	        throw err; // Stop if it's a hard limit
79	      }
80	    }
81	  }
82	  throw lastError || new Error(`Failed to fetch ${kind} data from all available Binance endpoints.`);
83	}
84	
85	/**
86	 * İç kullanım: Büyük tarih aralıklarında kline'ları sayfalı (paginated) çeker.
87	 */
88	async function fetchAllKlines(kind, symbol, startMs, endMs, market = "futures", interval = "1m") {
89	  const MAX_LIMIT = 1500;
90	  let cur = startMs;
91	  const out = [];
92	  let guard = 0;
93	
94	  // Interval duration in ms
95	  let stepMs = 60_000;
96	  if (interval === "1h") stepMs = 3600_000;
97	  if (interval === "1d") stepMs = 86400_000;
98	
99	  while (cur < endMs && guard++ < 1000) {
100	    const bases = market === "futures" ? F_BASES : S_BASES;
101	    const path = market === "futures"
102	      ? (kind === "mark" ? `/fapi/v1/markPriceKlines` : `/fapi/v1/klines`)
103	      : `/api/v3/klines`;
104	
105	    const fullPath = `${path}?symbol=${encodeURIComponent(symbol)}&interval=${interval}&startTime=${cur}&endTime=${endMs}&limit=${MAX_LIMIT}`;
106	
107	    const chunk = await fetchWithFallback(bases, fullPath, kind);
108	
109	    if (!Array.isArray(chunk) || !chunk.length) break;
110	
111	    out.push(...chunk);
112	
113	    const lastOpen = Number(chunk[chunk.length - 1][0]);
114	    const next = lastOpen + stepMs;
115	    if (next <= cur) break;
116	    cur = next;
117	  }
118	
119	  return out;
120	}
121	
122	/**
123	 * Tek bir dakikanın hem Mark hem de Last Price 1m mumunu çek
124	 * @param {string} symbol
125	 * @param {string} triggeredAtStr YYYY-MM-DD HH:MM:SS
126	 * @param {"futures"|"spot"} market
127	 */
128	export async function getTriggerMinuteCandles(symbol, triggeredAtStr, market = "futures") {
129	  const start = msMinuteStartUTC(triggeredAtStr);
130	  const end = start + 60 * 1000;
131	
132	  const parseCandle = (c) =>
133	    !c
134	      ? null
135	      : {
136	        open: parseFloat(c[1]),
137	        high: parseFloat(c[2]),
138	        low: parseFloat(c[3]),
139	        close: parseFloat(c[4]),
140	      };
141	
142	  // SPOT Handling
143	  if (market === "spot") {
144	    const path = `/api/v3/klines?symbol=${symbol}&interval=1m&startTime=${start}&endTime=${end}`;
145	    const spotJson = await fetchWithFallback(S_BASES, path, "Spot");
146	    return {
147	      mark: null,
148	      last: spotJson.length ? parseCandle(spotJson[0]) : null
149	    };
150	  }
151	
152	  // FUTURES Handling (Standard)
153	  const markPath = `/fapi/v1/markPriceKlines?symbol=${symbol}&interval=1m&startTime=${start}&endTime=${end}`;
154	  const markJson = await fetchWithFallback(F_BASES, markPath, "Mark Price");
155	
156	  const lastPath = `/fapi/v1/klines?symbol=${symbol}&interval=1m&startTime=${start}&endTime=${end}`;
157	  const lastJson = await fetchWithFallback(F_BASES, lastPath, "Last Price");
158	
159	  return {
160	    mark: markJson.length ? parseCandle(markJson[0]) : null,
161	    last: lastJson.length ? parseCandle(lastJson[0]) : null,
162	  };
163	}
164	
165	/**
166	 * Belirli aralıkta high/low (Mark + Last)
167	 * ⚠️ Büyük aralıklarda tüm veriyi sayfalı çeker (paginate).
168	 * @param {string} symbol
169	 * @param {string} fromStr
170	 * @param {string} toStr
171	 * @param {"futures"|"spot"} market
172	 */
173	export async function getRangeHighLow(symbol, fromStr, toStr, market = "futures") {
174	  const start = Date.parse(fromStr + "Z");
175	  const end = Date.parse(toStr + "Z");
176	  if (isNaN(start) || isNaN(end)) throw new Error("Invalid date format.");
177	  if (end <= start) throw new Error("End time must be after start time.");
178	
179	  // Spotta sadece Last (klines) verisi var.
180	  if (market === "spot") {
181	    const lastCandles = await fetchAllKlines("last", symbol, start, end, "spot", "1m");
182	
183	    let lastHigh, lastLow, lastHighTime, lastLowTime, lastOpen, lastClose;
184	    const isNum = (v) => typeof v === "number" && !isNaN(v);
185	
186	    if (lastCandles.length) {
187	      const highs = lastCandles.map((c) => parseFloat(c[2]));
188	      const lows = lastCandles.map((c) => parseFloat(c[3]));
189	      lastHigh = Math.max(...highs);
190	      lastLow = Math.min(...lows);
191	      const idxH = highs.indexOf(lastHigh);
192	      const idxL = lows.indexOf(lastLow);
193	      lastHighTime = fmtUTC(Number(lastCandles[idxH][0]));
194	      lastLowTime = fmtUTC(Number(lastCandles[idxL][0]));
195	      lastOpen = parseFloat(lastCandles[0][1]);
196	      lastClose = parseFloat(lastCandles[lastCandles.length - 1][4]);
197	    }
198	
199	    return {
200	      mark: { open: "N/A", high: "N/A", low: "N/A", close: "N/A", highTime: "N/A", lowTime: "N/A", changePct: "N/A" }, // Consistency
201	      last: {
202	        open: lastOpen ?? "N/A",
203	        high: lastHigh ?? "N/A",
204	        low: lastLow ?? "N/A",
205	        close: lastClose ?? "N/A",
206	        highTime: lastHighTime ?? "N/A",
207	        lowTime: lastLowTime ?? "N/A",
208	        changePct:
209	          (isNum(lastHigh) && isNum(lastLow) && lastLow !== 0)
210	            ? (((lastHigh - lastLow) / lastLow) * 100).toFixed(2) + "%"
211	            : "N/A",
212	      }
213	    };
214	  }
215	
216	  // FUTURES
217	  const [markCandles, lastCandles] = await Promise.all([
218	    fetchAllKlines("mark", symbol, start, end, "futures", "1m"),
219	    fetchAllKlines("last", symbol, start, end, "futures", "1m"),
220	  ]);
221	
222	  if (!markCandles.length && !lastCandles.length) {
223	    return {
224	      mark: { open: "N/A", high: "N/A", low: "N/A", close: "N/A", highTime: "N/A", lowTime: "N/A", changePct: "N/A" },
225	      last: { open: "N/A", high: "N/A", low: "N/A", close: "N/A", highTime: "N/A", lowTime: "N/A", changePct: "N/A" },
226	    };
227	  }
228	
229	  let markHigh, markLow, markHighTime, markLowTime, markOpen, markClose;
230	  if (markCandles.length) {
231	    const highs = markCandles.map((c) => parseFloat(c[2]));
232	    const lows = markCandles.map((c) => parseFloat(c[3]));
233	    markHigh = Math.max(...highs);
234	    markLow = Math.min(...lows);
235	    const idxH = highs.indexOf(markHigh);
236	    const idxL = lows.indexOf(markLow);
237	    markHighTime = fmtUTC(Number(markCandles[idxH][0]));
238	    markLowTime = fmtUTC(Number(markCandles[idxL][0]));
239	    markOpen = parseFloat(markCandles[0][1]);
240	    markClose = parseFloat(markCandles[markCandles.length - 1][4]);
241	  }
242	
243	  let lastHigh, lastLow, lastHighTime, lastLowTime, lastOpen, lastClose;
244	  if (lastCandles.length) {
245	    const highs = lastCandles.map((c) => parseFloat(c[2]));
246	    const lows = lastCandles.map((c) => parseFloat(c[3]));
247	    lastHigh = Math.max(...highs);
248	    lastLow = Math.min(...lows);
249	    const idxH = highs.indexOf(lastHigh);
250	    const idxL = lows.indexOf(lastLow);
251	    lastHighTime = fmtUTC(Number(lastCandles[idxH][0]));
252	    lastLowTime = fmtUTC(Number(lastCandles[idxL][0]));
253	    lastOpen = parseFloat(lastCandles[0][1]);
254	    lastClose = parseFloat(lastCandles[lastCandles.length - 1][4]);
255	  }
256	
257	  const isNum = (v) => typeof v === "number" && !isNaN(v);
258	
259	  return {
260	    mark: {
261	      open: markOpen ?? "N/A",
262	      high: markHigh ?? "N/A",
263	      low: markLow ?? "N/A",
264	      close: markClose ?? "N/A",
265	      highTime: markHighTime ?? "N/A",
266	      lowTime: markLowTime ?? "N/A",
267	      changePct:
268	        (isNum(markHigh) && isNum(markLow) && markLow !== 0)
269	          ? (((markHigh - markLow) / markLow) * 100).toFixed(2) + "%"
270	          : "N/A",
271	    },
272	    last: {
273	      open: lastOpen ?? "N/A",
274	      high: lastHigh ?? "N/A",
275	      low: lastLow ?? "N/A",
276	      close: lastClose ?? "N/A",
277	      highTime: lastHighTime ?? "N/A",
278	      lowTime: lastLowTime ?? "N/A",
279	      changePct:
280	        (isNum(lastHigh) && isNum(lastLow) && lastLow !== 0)
281	          ? (((lastHigh - lastLow) / lastLow) * 100).toFixed(2) + "%"
282	          : "N/A",
283	    },
284	  };
285	}
286	
287	/**
288	 * Last Price OHLC for a single second (via aggTrades, max 7 gün)
289	 * @param {string} symbol
290	 * @param {string} atStr
291	 * @param {"futures"|"spot"} market
292	 */
293	export async function getLastPriceAtSecond(symbol, atStr, market = "futures") {
294	  const start = Date.parse(atStr + "Z");
295	  if (isNaN(start)) throw new Error("Invalid date format.");
296	  const end = start + 1000;
297	
298	  // URL Config
299	  const bases = market === "futures" ? F_BASES : S_BASES;
300	  const path = market === "futures"
301	    ? `/fapi/v1/aggTrades?symbol=${symbol}&startTime=${start}&endTime=${end}&limit=1000`
302	    : `/api/v3/aggTrades?symbol=${symbol}&startTime=${start}&endTime=${end}&limit=1000`;
303	
304	  const trades = await fetchWithFallback(bases, path, "aggTrades");
305	  if (!trades.length) return null;
306	
307	  const prices = trades.map((t) => parseFloat(t.p));
308	  return {
309	    open: prices[0],
310	    high: Math.max(...prices),
311	    low: Math.min(...prices),
312	    close: prices[prices.length - 1],
313	    count: trades.length,
314	  };
315	}
316	
317	/**
318	 * 📌 Funding Rate & Mark Price (yakın funding kaydı)
319	 */
320	export async function getNearestFunding(symbol, targetUtcStr) {
321	  const targetMs = Date.parse(targetUtcStr + "Z");
322	  if (isNaN(targetMs)) throw new Error("Invalid date format.");
323	
324	  for (const windowMin of [10, 30, 90]) {
325	    const path = `/fapi/v1/fundingRate?symbol=${symbol.toUpperCase()}&startTime=${targetMs - windowMin * 60_000}&endTime=${targetMs + windowMin * 60_000}&limit=1000`;
326	    try {
327	      const rows = await fetchWithFallback(F_BASES, path, "fundingRate");
328	      if (rows && rows.length) {
329	        rows.sort(
330	          (a, b) =>
331	            Math.abs(parseInt(a.fundingTime) - targetMs) -
332	            Math.abs(parseInt(b.fundingTime) - targetMs)
333	        );
334	        const rec = rows[0];
335	        return {
336	          funding_time: fmtUTC(Number(rec.fundingTime)),
337	          funding_rate: parseFloat(rec.fundingRate),
338	          mark_price: rec.markPrice || null,
339	          funding_time_ms: Number(rec.fundingTime)
340	        };
341	      }
342	    } catch (e) {
343	      if (windowMin === 90) throw e; // Only throw on final attempt
344	    }
345	  }
346	  return null;
347	}
348	
349	/**
350	 * 📌 Eğer funding kaydında markPrice yoksa 1m kapanışı al (fallback)
351	 */
352	export async function getMarkPriceClose1m(symbol, fundingTimeMs) {
353	  const startMinute = fundingTimeMs - (fundingTimeMs % 60_000);
354	  const candidates = [startMinute, startMinute - 60_000];
355	  for (const start of candidates) {
356	    const path = `/fapi/v1/markPriceKlines?symbol=${symbol.toUpperCase()}&interval=1m&startTime=${start}&limit=1`;
357	    try {
358	      const data = await fetchWithFallback(F_BASES, path, "Mark Price fallback");
359	      if (Array.isArray(data) && data.length) {
360	        return {
361	          mark_price: parseFloat(data[0][4]),
362	          close_time: fmtUTC(Number(data[0][6]))
363	        };
364	      }
365	    } catch (e) {
366	      // Continue to next candidate
367	    }
368	  }
