554	 * 1. Wait for Activation Price (if provided)
555	 * 2. Track Peak (Sell/Short) or Trough (Buy/Long)
556	 * 3. Trigger when price deviates by callbackRate from Peak/Trough
557	 */
558	export async function checkTrailingStop(symbol, fromStr, toStr, activationPrice, callbackRate, direction, market = "futures", priceType = "last") {
559	  // Normalize range to minute boundaries to ensure we get at least one 1m candle from Binance
560	  let startMs = Date.parse(fromStr + "Z");
561	  let endMs = Date.parse(toStr + "Z");
562	  if (isNaN(startMs) || isNaN(endMs)) throw new Error("Invalid date format.");
563	
564	  if (endMs <= startMs) {
565	    // If range is virtually instant or backward, extend to at least 1 minute
566	    endMs = startMs + 60000;
567	  }
568	
569	  // Align to minute start for the fetch to avoid empty responses from Binance
570	  const fetchStart = Math.floor(startMs / 60000) * 60000;
571	  const fetchEnd = Math.ceil(endMs / 60000) * 60000;
572	
573	  const fetchKind = priceType === "mark" ? "mark" : "last";
574	  // Fetch 1m candles for the whole range
575	  const candles = await fetchAllKlines(fetchKind, symbol, fetchStart, fetchEnd, market, "1m");
576	
577	  if (!candles.length) return { status: "not_found" };
578	
579	  let isActivated = !activationPrice; // If no activation price, it's active immediately
580	  let activationTime = null;
581	  let peakPrice = direction === "short" ? -Infinity : Infinity; // Highest High for Sell, Lowest Low for Buy
582	  let peakTime = null;
583	  let triggerTime = null;
584	  let triggerPrice = null;
585	  let maxObservedCallback = 0; // The closest the price got to triggering in %
586	
587	  // Used only for logging or internal logic if needed, but not actively used in loop
588	  // const cbMultiplier = callbackRate / 100; 
589	
590	  for (const c of candles) {
591	    const t = Number(c[0]);
592	    const o = parseFloat(c[1]);
593	    const h = parseFloat(c[2]);
594	    const l = parseFloat(c[3]);
595	    const cl = parseFloat(c[4]);
596	
597	    // To be conservative and avoid "look-ahead" bias in 1m OHLC:
598	    // Short (Sell): Assume price hits Low BEFORE High (delays trigger)
599	    // Long (Buy): Assume price hits High BEFORE Low (delays trigger)
600	    const subPoints = direction === "short" ? [o, l, h, cl] : [o, h, l, cl];
601	
602	    for (const p of subPoints) {
603	      // Phase 1: Activation
604	      if (!isActivated) {
605	        if (direction === "short" ? p >= activationPrice : p <= activationPrice) {
606	          isActivated = true;
607	          activationTime = fmtUTC(t);
608	          peakPrice = p; // Start tracking from activation point
609	          peakTime = fmtUTC(t);
610	        }
611	        if (!isActivated) continue;
612	      }
613	
614	      // Phase 2 & 3: Tracking Peak and checking Trigger
615	      // Update Peak/Trough
616	      if (direction === "short") {
617	        if (p > peakPrice) {
618	          peakPrice = p;
619	          peakTime = fmtUTC(t);
620	        }
621	      } else {
622	        if (p < peakPrice) {
623	          peakPrice = p;
624	          peakTime = fmtUTC(t);
625	        }
626	      }
627	
628	      // Check Trigger Condition
629	      const currentDev = direction === "short"
630	        ? ((peakPrice - p) / peakPrice) * 100
631	        : ((p - peakPrice) / peakPrice) * 100;
632	
633	      if (currentDev > maxObservedCallback) {
634	        maxObservedCallback = currentDev;
635	      }
636	
637	      if (currentDev >= callbackRate) {
638	        triggerTime = fmtUTC(t);
639	        triggerPrice = direction === "short"
640	          ? peakPrice * (1 - callbackRate / 100)
641	          : peakPrice * (1 + callbackRate / 100);
642	
643	        // --- ENHANCEMENT: Second Precision ---
644	        if (priceType === "last" && market === "futures") {
645	          try {
646	            const bases = F_BASES;
647	            const trades = await fetchWithFallback(bases, `/fapi/v1/aggTrades?symbol=${symbol}&startTime=${t}&endTime=${t + 59999}`, "AggTrades");
648	            if (trades && trades.length) {
649	              let localPeak = peakPrice;
650	              let searchIsActivated = isActivated && activationTime !== fmtUTC(t);
651	
652	              for (const tr of trades) {
653	                const tp = parseFloat(tr.p);
654	                const ts = Number(tr.T);
655	
656	                if (!searchIsActivated) {
657	                  if (direction === "short" ? tp >= activationPrice : tp <= activationPrice) {
658	                    searchIsActivated = true;
659	                    activationTime = fmtUTC(ts);
660	                    localPeak = tp;
661	                  }
662	                }
663	
664	                if (searchIsActivated) {
665	                  if (direction === "short") {
666	                    if (tp > localPeak) localPeak = tp;
667	                    if (tp <= localPeak * (1 - callbackRate / 100)) {
668	                      triggerTime = fmtUTC(ts);
669	                      triggerPrice = localPeak * (1 - callbackRate / 100);
670	                      break;
671	                    }
672	                  } else {
673	                    if (tp < localPeak) localPeak = tp;
674	                    if (tp >= localPeak * (1 + callbackRate / 100)) {
675	                      triggerTime = fmtUTC(ts);
676	                      triggerPrice = localPeak * (1 + callbackRate / 100);
677	                      break;
678	                    }
679	                  }
680	                }
681	              }
682	              peakPrice = localPeak;
683	            }
684	          } catch (e) {
685	            console.warn("Precision fetch failed:", e);
686	          }
687	        }
688	        break;
689	      }
690	    }
691	    if (triggerTime) break;
692	  }
693	
694	  return {
695	    status: triggerTime ? "triggered" : (isActivated ? "activated_no_trigger" : "not_activated"),
696	    isActivated,
697	    activationTime,
698	    peakPrice: peakPrice === -Infinity || peakPrice === Infinity ? null : peakPrice,
699	    peakTime,
700	    triggerTime,
701	    triggerPrice,
702	    maxObservedCallback,
703	    isEstimated: priceType === "mark" && isActivated && triggerTime && (activationTime === triggerTime || peakTime === triggerTime),
704	    symbol,
705	    period: `${fromStr} -> ${toStr}`
706	  };
707	}
