3	/**
4	 * Format number safely with fixed digits.
5	 * If precision is provided, use it. Otherwise default to 8.
6	 */
7	export function fmtNum(v, digits = 8) {
8	  if (v === null || v === undefined || Number.isNaN(v)) return "N/A";
9	  const n = Number(v);
10	  if (!Number.isFinite(n)) return String(v);
11	
12	  return n.toFixed(digits);
13	}
14	
15	// Convert string to uppercase safely
16	export function upper(s) {
17	  return (s || "").toString().trim().toUpperCase();
18	}
19	
20	// Build user-friendly status line with timestamp
21	export function statusLineFriendly(inputs) {
22	  const st = upper(inputs.status);
23	
24	  // 'final_status_utc' (Stop-Limit, Not-Reached) önceliklidir.
25	  // Yoksa, 'triggered_at_utc' (SL/TP Slippage) kullanılır.
26	  const t = inputs.final_status_utc || inputs.triggered_at_utc || "";
27	
28	  if (st === "CANCELED" || st === "CANCELLED") {
29	    return `${t} UTC+0 = This is the date and time the order was **cancelled**.`;
30	  } else if (st === "EXECUTED") {
31	    return `${t} UTC+0 = This is the date and time your order **executed**.`;
32	  } else if (st === "TRIGGERED") {
33	    // Bu 'Stop-Limit' için 'Triggered At' ile çakışmayacak,
34	    // çünkü 'Stop-Limit' 'final_status_utc' kullanır.
35	    return `${t} UTC+0 = This is the date and time the order was **triggered**.`;
36	  } else if (st === "OPEN") {
37	    return `${t} UTC+0 = Current status: **OPEN** (order still active).`;
38	  } else if (st === "EXPIRED") {
39	    return `${t} UTC+0 = This is the date and time the order **expired**.`;
40	  }
